import json

def parse_series(series_str: str) -> dict[str, Any]:
    return json.loads(series_str)

def merge_series(series_list: list[dict[str, Any]]) -> dict[str, Any]:
    merged = {}
    for series in series_list:
        for ts, value in zip(series["timestamps"], series["values"]):
            if ts in merged:
                merged[ts].append(value)
            else:
                merged[ts] = [value]
    for ts, values in merged.items():
        merged[ts] = sum(values) / len(values)
    sorted_ts = sorted(merged)
    return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}

def moving_average(series: dict[str, Any], window_size: int) -> list[float]:
    values = series["values"]
    result = []
    for i in range(len(values)):
        start = max(0, i - window_size + 1)
        window = values[start : i + 1]
        result.append(sum(window) / len(window))
    return result

def solve(series_list: list[str], threshold: float) -> list[int]:
    parsed_series = [parse_series(series) for series in series_list]
    merged_series = merge_series(parsed_series)
    ma_values = moving_average(merged_series, 2)
    return [
        ts
        for ts, value in zip(merged_series["timestamps"], ma_values)
        if value > threshold
    ]
